	"github.com/stretchr/testify/require"
)

func scrubbedGitEnv() []string {
	env := os.Environ()
	out := make([]string, 0, len(env)+1)
	for _, kv := range env {
		if strings.HasPrefix(kv, "GIT_") {
			continue
		}
		out = append(out, kv)
	}
	return append(out, "GIT_CONFIG_NOSYSTEM=1")
}

func initTrackerLockRepo(t *testing.T) string {
	t.Helper()

	root := t.TempDir()
	run := func(args ...string) {
		cmd := exec.Command("git", args...)
		cmd.Dir = root
		cmd.Env = scrubbedGitEnv()
		out, err := cmd.CombinedOutput()
		if err != nil {
			t.Fatalf("git %v: %v\n%s", args, err, out)
		}
	}

	run("init", "-b", "main")
	run("config", "user.email", "test@ddx.test")
	run("config", "user.name", "DDx Test")

	require.NoError(t, os.WriteFile(filepath.Join(root, "seed.txt"), []byte("seed\n"), 0o644))
	run("add", "seed.txt")
	run("commit", "-m", "chore: initial seed")

	require.NoError(t, os.MkdirAll(filepath.Join(root, ddxroot.DirName), 0o755))
	return root
}

// TestLockCap_DefaultIndexLockCap10s asserts the default cap for
// .git/index.lock is 10s and is overridable via DDX_LOCK_CAP_INDEX_MS.
func TestLockCap_DefaultIndexLockCap10s(t *testing.T) {
	t.Setenv("DDX_LOCK_CAP_INDEX_MS", "")
	assert.Equal(t, 10*time.Second, CapFor("index.lock"),
		"default index.lock cap must be 10s")

	t.Setenv("DDX_LOCK_CAP_INDEX_MS", "2500")
	assert.Equal(t, 2500*time.Millisecond, CapFor("index.lock"),
		"index.lock cap must be configurable via DDX_LOCK_CAP_INDEX_MS")
}

// TestLockCap_ExceedingCapForceReleases asserts that holding past the cap
// triggers a forced release and the underlying lock file is removed.
func TestLockCap_ExceedingCapForceReleases(t *testing.T) {
	SetSink(nil)
	dir := t.TempDir()
	lockPath := filepath.Join(dir, "index.lock")
	require.NoError(t, os.WriteFile(lockPath, []byte("held"), 0o644))

	cfg := CapConfig{Cap: 30 * time.Millisecond, LockPath: lockPath, EvidenceDir: dir}
	err := InstrumentCapped("index.lock", "index.commit", cfg, func() error {
		time.Sleep(200 * time.Millisecond)
		return nil
	})
	require.NoError(t, err)

	_, statErr := os.Stat(lockPath)
	assert.True(t, os.IsNotExist(statErr),
		"lock file must be force-released after exceeding the cap")
}

// TestLockCap_ExceedingCapRemovesLockRecreatedAfterWatchdog asserts the
// release path cleans up a lock file recreated by a slow git subprocess after
// the watchdog's first forced removal.
func TestLockCap_ExceedingCapRemovesLockRecreatedAfterWatchdog(t *testing.T) {
	SetSink(nil)
	dir := t.TempDir()
	lockPath := filepath.Join(dir, "index.lock")
	require.NoError(t, os.WriteFile(lockPath, []byte("held"), 0o644))

	cfg := CapConfig{Cap: 30 * time.Millisecond, LockPath: lockPath, EvidenceDir: dir}
	err := InstrumentCapped("index.lock", "index.commit", cfg, func() error {
		time.Sleep(100 * time.Millisecond)
		require.NoError(t, os.WriteFile(lockPath, []byte("recreated"), 0o644))
		return nil
	})
	require.NoError(t, err)

	_, statErr := os.Stat(lockPath)
	assert.True(t, os.IsNotExist(statErr),
		"release path must remove lock files recreated after the cap watchdog fires")
}

// TestLockCap_ViolationWrittenToEvidence asserts a lock-violation.json appears
// under the worker's evidence directory carrying the required fields.
func TestLockCap_ViolationWrittenToEvidence(t *testing.T) {
	SetSink(nil)
	dir := t.TempDir()
	evidence := filepath.Join(dir, "20260527T021507-08bcbb0f")
	lockPath := filepath.Join(dir, "index.lock")
	require.NoError(t, os.WriteFile(lockPath, []byte("held"), 0o644))

	cfg := CapConfig{Cap: 30 * time.Millisecond, LockPath: lockPath, EvidenceDir: evidence}
	require.NoError(t, InstrumentCapped("index.lock", "index.commit", cfg, func() error {
		time.Sleep(200 * time.Millisecond)
		return nil
	}))

	data, err := os.ReadFile(filepath.Join(evidence, "lock-violation.json"))
	require.NoError(t, err, "lock-violation.json must exist under the evidence dir")

	var v Violation
	require.NoError(t, json.Unmarshal(data, &v))
	assert.Equal(t, "index.lock", v.LockName)
	assert.Equal(t, int64(30), v.CapMS)
	assert.GreaterOrEqual(t, v.ActualHoldMS, int64(30),
		"actual_hold_ms must be at least the cap")
	assert.Equal(t, os.Getpid(), v.HolderPID)
	assert.NotEmpty(t, v.Stack, "violation record must include a stack trace")
}

// TestLockCap_ViolationLoggedAsError asserts an error-severity event is
// emitted via the metric helper when the cap is exceeded.
func TestLockCap_ViolationLoggedAsError(t *testing.T) {
	snapshot := capture(t)
	dir := t.TempDir()
	lockPath := filepath.Join(dir, "index.lock")
	require.NoError(t, os.WriteFile(lockPath, []byte("held"), 0o644))

	cfg := CapConfig{Cap: 30 * time.Millisecond, LockPath: lockPath, EvidenceDir: dir}
	require.NoError(t, InstrumentCapped("index.lock", "index.commit", cfg, func() error {
		time.Sleep(200 * time.Millisecond)
		return nil
	}))

	var violation *Event
	for _, ev := range snapshot() {
		if ev.Event == "violation" {
			ev := ev
			violation = &ev
		}
	}
	require.NotNil(t, violation, "expected a violation event")
	assert.Equal(t, "error", violation.Severity)
	assert.Equal(t, "index.lock", violation.LockName)
	assert.Equal(t, int64(30), violation.CapMS)
}

// TestLockCap_WithinCapDoesNotForceRelease asserts that a hold under the cap
// neither removes the lock nor records a violation.
func TestLockCap_WithinCapDoesNotForceRelease(t *testing.T) {
	snapshot := capture(t)
	dir := t.TempDir()
	lockPath := filepath.Join(dir, "index.lock")
	require.NoError(t, os.WriteFile(lockPath, []byte("held"), 0o644))

	cfg := CapConfig{Cap: 200 * time.Millisecond, LockPath: lockPath, EvidenceDir: dir}
	require.NoError(t, InstrumentCapped("index.lock", "index.commit", cfg, func() error {
		return nil
	}))

	_, statErr := os.Stat(lockPath)
	assert.NoError(t, statErr, "lock file must survive a within-cap hold")
	_, vErr := os.Stat(filepath.Join(dir, "lock-violation.json"))
	assert.True(t, os.IsNotExist(vErr), "no violation record for a within-cap hold")
	for _, ev := range snapshot() {
		assert.NotEqual(t, "violation", ev.Event, "no violation event for a within-cap hold")
	}
}

// TestLockCap_DefaultTrackerLockCap30s asserts the default cap for
// .ddx/.git-tracker.lock is 30s and is overridable via DDX_LOCK_CAP_TRACKER_MS.
func TestLockCap_DefaultTrackerLockCap30s(t *testing.T) {
	t.Setenv("DDX_LOCK_CAP_TRACKER_MS", "")
	assert.Equal(t, 30*time.Second, CapFor("tracker.lock"))

	t.Setenv("DDX_LOCK_CAP_TRACKER_MS", "5000")
	assert.Equal(t, 5*time.Second, CapFor("tracker.lock"))
}

// TestLockCap_NoEnforcementWhenDisabled asserts that with cap enforcement off
// (the default), Instrument resolves no cap for the named locks.
func TestLockCap_NoEnforcementWhenDisabled(t *testing.T) {
	SetCapEnforcement("", "")
	t.Cleanup(func() { SetCapEnforcement("", "") })
	assert.Equal(t, CapConfig{}, resolveCapConfig("index.lock"))
	assert.Equal(t, CapConfig{}, resolveCapConfig("tracker.lock"))
}

// TestLockCap_EnforcementResolvesLockPaths asserts that enabling enforcement
// resolves the on-disk lock paths for the two named locks under projectRoot.
func TestLockCap_EnforcementResolvesLockPaths(t *testing.T) {
	root := t.TempDir()
	SetCapEnforcement(root, filepath.Join(root, "evidence"))
	t.Cleanup(func() { SetCapEnforcement("", "") })

	idx := resolveCapConfig("index.lock")
	assert.Equal(t, filepath.Join(root, ".git", "index.lock"), idx.LockPath)
	assert.Greater(t, idx.Cap, time.Duration(0))

	trk := resolveCapConfig("tracker.lock")
	assert.Contains(t, trk.LockPath, ".git-tracker.lock")
	assert.Greater(t, trk.Cap, time.Duration(0))
}

// TestLockCap_TrackerLockPathUsesSharedMainGitRoot asserts that tracker.lock
// cap enforcement resolves through the shared main-worktree DDx root when the
// request originates from a linked worktree.
func TestLockCap_TrackerLockPathUsesSharedMainGitRoot(t *testing.T) {
	root := initTrackerLockRepo(t)
	linked := filepath.Join(t.TempDir(), "linked")
	runGit := func(args ...string) {
		cmd := exec.Command("git", args...)
		cmd.Dir = root
		cmd.Env = scrubbedGitEnv()
		out, err := cmd.CombinedOutput()
		if err != nil {
			t.Fatalf("git %v: %v\n%s", args, err, out)
		}
	}

	runGit("worktree", "add", "--detach", linked)
	t.Cleanup(func() { runGit("worktree", "remove", "--force", linked) })
	t.Cleanup(func() { SetCapEnforcement("", "") })

	SetCapEnforcement(linked, filepath.Join(linked, "evidence"))

	trk := resolveCapConfig("tracker.lock")
	wantRoot := SharedMainGitLockRoot(linked)
	assert.Equal(t, root, wantRoot, "linked worktrees must resolve tracker caps through the primary workspace")
	assert.Equal(t, filepath.Join(root, ddxroot.DirName, ".git-tracker.lock"), trk.LockPath)
	assert.Equal(t, filepath.Join(wantRoot, ddxroot.DirName, ".git-tracker.lock"), trk.LockPath)
	assert.Greater(t, trk.Cap, time.Duration(0))
}

package agent

import (
	"bytes"
	"context"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/config"
	internalgit "github.com/DocumentDrivenDX/ddx/internal/git"
)

// checkpointPreDispatchDirt captures DDx bookkeeping changes as a commit on
// the current branch without using the caller checkout's real index or commit
// hooks. The checkpoint is intentionally narrow: if the parent checkout also
// contains ordinary implementation files, the attempt fails with an actionable
// error so those changes can be committed in the bead's substantive
// [ddx-<id>] commit instead of being folded into the checkpoint.
const preDispatchCheckpointDirtyRefusalPrefix = "checkpoint refused to absorb implementation changes outside DDx bookkeeping: "
const preDispatchDirtyPreserveRefPrefix = "refs/ddx/pre-dispatch/"

// PreDispatchDirtyPreservation records the recoverable handle DDx created when
// it preserved implementation dirt before a watch-mode redispatch.
type PreDispatchDirtyPreservation struct {
	DirtyPaths     []string
	PreserveRef    string
	RecoverCommand string
}

var preDispatchDirtyPathLister = func(projectRoot string) ([]string, error) {
	return preDispatchCheckpointDirtyPaths(projectRoot)
}

var preDispatchCheckpointBeforeUpdateRef = func(projectRoot, ref, commit, head string) {}

func normalizePreDispatchDirtyPaths(paths []string) []string {
	seen := make(map[string]bool, len(paths))
	normalized := make([]string, 0, len(paths))
	for _, path := range paths {
		path = filepath.ToSlash(strings.TrimSpace(path))
		if path == "" || seen[path] {
			continue
		}
		seen[path] = true
		normalized = append(normalized, path)
	}
	sort.Strings(normalized)
	return normalized
}

func intersectPreDispatchDirtyPaths(current, want []string) []string {
	if len(current) == 0 || len(want) == 0 {
		return nil
	}
	wantSet := make(map[string]bool, len(want))
	for _, path := range want {
		wantSet[path] = true
	}
	var overlap []string
	for _, path := range current {
		if wantSet[path] {
			overlap = append(overlap, path)
		}
	}
	sort.Strings(overlap)
	return overlap
}

func classifyPreDispatchDirtyPaths(dirtyPaths []string) (allowedPaths, blockedPaths []string) {
	for _, path := range normalizePreDispatchDirtyPaths(dirtyPaths) {
		if preDispatchCheckpointAllowedPath(path) {
			allowedPaths = append(allowedPaths, path)
			continue
		}
		blockedPaths = append(blockedPaths, path)
	}
	return allowedPaths, blockedPaths
}

// stablePreDispatchImplementationDirtyPaths re-reads the project dirt and only
// treats implementation paths as actionable when they survive the immediate
// recheck. This filters transient rename/delete paths that can briefly appear
// in watch mode right after a successful land.
func stablePreDispatchImplementationDirtyPaths(projectRoot string, dirtyPaths []string) ([]string, []string, error) {
	normalized := normalizePreDispatchDirtyPaths(dirtyPaths)
	if projectRoot == "" || len(normalized) == 0 {
		return normalized, normalized, nil
	}

	currentPaths, err := preDispatchDirtyPathLister(projectRoot)
	if err != nil {
		return nil, nil, fmt.Errorf("rechecking pre-dispatch dirt: %w", err)
	}
	return intersectPreDispatchDirtyPaths(currentPaths, normalized), currentPaths, nil
}

func resolveOptionalGitRef(dir, ref string) (string, bool) {
	out, err := internalgit.Command(context.Background(), dir, "rev-parse", "-q", "--verify", ref).Output()
	if err != nil {
		return "", false
	}
	sha := strings.TrimSpace(string(out))
	if sha == "" {
		return "", false
	}
	return sha, true
}

func preDispatchDirtyRecoverCommand(preserveRef string) string {
	if preserveRef == "" {
		return ""
	}
	return "git stash apply " + preserveRef
}

func preservePreDispatchDirtyPaths(projectRoot string, dirtyPaths []string) (*PreDispatchDirtyPreservation, error) {
	if projectRoot == "" {
		return nil, fmt.Errorf("project root is required for pre-dispatch dirty preservation")
	}
	normalized := normalizePreDispatchDirtyPaths(dirtyPaths)
	if len(normalized) == 0 {
		return nil, fmt.Errorf("no dirty implementation paths to preserve")
	}

	var preserved *PreDispatchDirtyPreservation
	if err := withTrackerLock(projectRoot, "preserve_dirt", func() error {
		var err error
		preserved, err = preservePreDispatchDirtyPathsLocked(projectRoot, normalized)
		return err
	}); err != nil {
		return nil, err
	}
	return preserved, nil
}

func preservePreDispatchDirtyPathsLocked(projectRoot string, dirtyPaths []string) (*PreDispatchDirtyPreservation, error) {
	if err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--is-inside-work-tree").Run(); err != nil {
		return nil, fmt.Errorf("verifying project worktree for pre-dispatch preservation: %w", err)
	}
	if out, err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--verify", "HEAD").CombinedOutput(); err != nil {
		return nil, fmt.Errorf("resolving HEAD for pre-dispatch preservation: %s: %w", strings.TrimSpace(string(out)), err)
	}

	stashBefore, _ := resolveOptionalGitRef(projectRoot, "refs/stash")
	preserveID := GenerateAttemptID()
	preserveRef := preDispatchDirtyPreserveRefPrefix + preserveID
	stashMsg := "ddx pre-dispatch preserve " + preserveID
	stashArgs := []string{"stash", "push", "--include-untracked", "--message", stashMsg, "--"}
	stashArgs = append(stashArgs, dirtyPaths...)
	if out, err := internalgit.Command(context.Background(), projectRoot, stashArgs...).CombinedOutput(); err != nil {
		return nil, fmt.Errorf("preserving pre-dispatch dirty implementation paths: %s: %w", strings.TrimSpace(string(out)), err)
	}

	stashAfter, ok := resolveOptionalGitRef(projectRoot, "refs/stash")
	if !ok || stashAfter == "" || stashAfter == stashBefore {
		return nil, fmt.Errorf("preserving pre-dispatch dirty implementation paths did not create a recoverable stash entry")
	}
	if out, err := internalgit.Command(context.Background(), projectRoot, "update-ref", preserveRef, stashAfter).CombinedOutput(); err != nil {
		return nil, fmt.Errorf("pinning pre-dispatch dirty preservation ref: %s: %w", strings.TrimSpace(string(out)), err)
	}
	_, _ = internalgit.Command(context.Background(), projectRoot, "stash", "drop", "stash@{0}").CombinedOutput()

	remainingPaths, err := preDispatchDirtyPathLister(projectRoot)
	if err != nil {
		return nil, fmt.Errorf("verifying preserved pre-dispatch dirt: %w", err)
	}
	if overlap := intersectPreDispatchDirtyPaths(remainingPaths, dirtyPaths); len(overlap) > 0 {
		return nil, fmt.Errorf("preserving pre-dispatch dirty implementation paths left the project worktree dirty: %s", strings.Join(overlap, ", "))
	}

	return &PreDispatchDirtyPreservation{
		DirtyPaths:     append([]string(nil), dirtyPaths...),
		PreserveRef:    preserveRef,
		RecoverCommand: preDispatchDirtyRecoverCommand(preserveRef),
	}, nil
}

func checkpointPreDispatchDirt(projectRoot, attemptID string) (bool, error) {
	workTreeOut, err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--is-inside-work-tree").CombinedOutput()
	if err != nil {
		return false, nil
	}
	if strings.TrimSpace(string(workTreeOut)) != "true" {
		return false, fmt.Errorf("verifying project worktree for pre-dispatch checkpoint: git rev-parse --is-inside-work-tree returned %q", strings.TrimSpace(string(workTreeOut)))
	}
	headOut, err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--verify", "HEAD").CombinedOutput()
	if err != nil {
		return false, nil
	}
	head := strings.TrimSpace(string(headOut))
	if head == "" {
		return false, nil
	}

	skipWorktreePaths, err := checkpointSkipWorktreePaths(projectRoot)
	if err != nil {
		return false, err
	}

	dirtyPaths, err := preDispatchDirtyPathLister(projectRoot)
	if err != nil {
		return false, err
	}
	if len(dirtyPaths) == 0 {
		return false, nil
	}

	allowedPaths, blockedPaths := classifyPreDispatchDirtyPaths(dirtyPaths)
	if len(blockedPaths) > 0 {
		stableBlockedPaths, currentDirtyPaths, err := stablePreDispatchImplementationDirtyPaths(projectRoot, blockedPaths)
		if err != nil {
			return false, err
		}
		if len(stableBlockedPaths) > 0 {
			return false, fmt.Errorf(
				"%s%s; commit or clean those files before rerunning so the bead's [ddx-<id>] substantive commit stays intentional",
				preDispatchCheckpointDirtyRefusalPrefix,
				strings.Join(stableBlockedPaths, ", "),
			)
		}
		allowedPaths, _ = classifyPreDispatchDirtyPaths(currentDirtyPaths)
	}
	if len(allowedPaths) == 0 {
		return false, nil
	}

	indexFile, err := config.CreateExecutionScratch(projectRoot, "ddx-pre-dispatch-index-*")
	if err != nil {
		return false, fmt.Errorf("creating temp checkpoint index: %w", err)
	}
	indexPath := indexFile.Name()
	_ = indexFile.Close()
	_ = os.Remove(indexPath)
	defer func() { _ = os.Remove(indexPath) }()

	gitWithIndex := func(args ...string) ([]byte, error) {
		cmd := internalgit.Command(context.Background(), projectRoot, args...)
		cmd.Env = append(cmd.Env, "GIT_INDEX_FILE="+indexPath)
		return cmd.CombinedOutput()
	}

	refOut, _ := internalgit.Command(context.Background(), projectRoot, "symbolic-ref", "-q", "HEAD").Output()
	ref := strings.TrimSpace(string(refOut))
	if ref == "" {
		ref = "HEAD"
	}

	const maxCheckpointRefAttempts = 3
	for attempt := 1; attempt <= maxCheckpointRefAttempts; attempt++ {
		headOut, err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--verify", "HEAD").CombinedOutput()
		if err != nil {
			return false, fmt.Errorf("resolving checkpoint HEAD: %s: %w", strings.TrimSpace(string(headOut)), err)
		}
		head = strings.TrimSpace(string(headOut))
		if head == "" {
			return false, nil
		}

		if out, err := gitWithIndex("read-tree", "HEAD"); err != nil {
			return false, fmt.Errorf("initializing checkpoint index: %s: %w", strings.TrimSpace(string(out)), err)
		}

		addArgs := []string{"add", "-A", "--force", "--"}
		addArgs = append(addArgs, allowedPaths...)
		if out, err := gitWithIndex(addArgs...); err != nil {
			return false, fmt.Errorf("staging checkpoint changes: %s: %w", strings.TrimSpace(string(out)), err)
		}

		changedOut, err := gitWithIndex("diff", "--cached", "--name-only")
		if err != nil {
			return false, fmt.Errorf("checking checkpoint diff: %w", err)
		}
		if len(bytes.TrimSpace(changedOut)) == 0 {
			return false, nil
		}

		treeOut, err := gitWithIndex("write-tree")
		if err != nil {
			return false, fmt.Errorf("writing checkpoint tree: %s: %w", strings.TrimSpace(string(treeOut)), err)
		}
		tree := strings.TrimSpace(string(treeOut))
		msg := "chore: checkpoint pre-execute-bead " + attemptID
		commitOut, err := internalgit.Command(context.Background(), projectRoot,
			"-c", "user.name=ddx-checkpoint",
			"-c", "user.email=checkpoint@ddx.local",
			"commit-tree", tree, "-p", head, "-m", msg,
		).CombinedOutput()
		if err != nil {
			return false, fmt.Errorf("creating checkpoint commit: %s: %w", strings.TrimSpace(string(commitOut)), err)
		}
		commit := strings.TrimSpace(string(commitOut))

		preDispatchCheckpointBeforeUpdateRef(projectRoot, ref, commit, head)
		out, err := internalgit.Command(context.Background(), projectRoot, "update-ref", ref, commit, head).CombinedOutput()
		if err == nil {
			if out, err := runGitWithIndexLockRecovery(context.Background(), projectRoot, "read-tree", "HEAD"); err != nil {
				return false, fmt.Errorf("syncing checkpoint index: %s: %w", strings.TrimSpace(string(out)), err)
			}
			if err := restoreCheckpointSkipWorktreePaths(projectRoot, skipWorktreePaths); err != nil {
				return false, err
			}
			return true, nil
		}

		refErrMsg := strings.TrimSpace(string(out))
		if attempt < maxCheckpointRefAttempts && IsLockContentionError(refErrMsg) {
			continue
		}
		return false, fmt.Errorf("advancing checkpoint ref: %s: %w", refErrMsg, err)
	}
	return false, fmt.Errorf("advancing checkpoint ref exceeded retry budget")
}

func checkpointSkipWorktreePaths(projectRoot string) ([]string, error) {
	out, err := internalgit.Command(context.Background(), projectRoot, "ls-files", "-t", "-z").CombinedOutput()
	if err != nil {
		return nil, fmt.Errorf("listing skip-worktree paths: %s: %w", strings.TrimSpace(string(out)), err)
	}
	var paths []string
	for len(out) > 0 {
		recordEnd := bytes.IndexByte(out, 0)
		if recordEnd == -1 {
			recordEnd = len(out)
		}
		record := out[:recordEnd]
		if recordEnd < len(out) {
			out = out[recordEnd+1:]
		} else {
			out = nil
		}
		if len(record) < 3 || record[0] != 'S' || record[1] != ' ' {
			continue
		}
		path := filepath.ToSlash(string(record[2:]))
		if path != "" {
			paths = append(paths, path)
		}

		record.Error = waitErr.Error()
		record.LastError = waitErr.Error()
	} else {
		record.State = "exited"
		record.Status = "exited"
	}
	if preservedState != "" {
		record.State = preservedState
		record.Status = preservedState
		record.Error = ""
	}
	if preservedState == "" && record.Managed && isTerminalWorkerState(record.State) {
		projectRoot := record.ProjectRoot
		if projectRoot == "" {
			projectRoot = m.projectRoot
		}
		beadID := record.CurrentBead
		if record.CurrentAttempt != nil && record.CurrentAttempt.BeadID != "" {
			beadID = record.CurrentAttempt.BeadID
		}
		body := fmt.Sprintf("worker=%s state=%s reason=worker-exit error=%s", record.ID, record.State, record.LastError)
		released := releaseWorkerClaims(projectRoot, record.ID, beadID, finishedAt, bead.BeadEvent{
			Kind:      "bead.reaped",
			Summary:   "worker-exit",
			Body:      body,
			Actor:     "ddx-server",
			Source:    "server-workers",
			CreatedAt: finishedAt,
		})
		if beadID == "" && len(released) > 0 {
			record.CurrentBead = released[0]
		}
	}
	m.mu.Unlock()

	if record.Managed && record.PID > 0 && isTerminalWorkerState(record.State) {
		if cleanupEvent, ok := recoverManagedWorkerIndexLockAfterExit(record.ProjectRoot, record.ID, record.PID); ok {
			record.Lifecycle = append(record.Lifecycle, cleanupEvent)
		}
	}

	m.mu.Lock()
	_ = m.writeRecord(dir, record)
	handle.record = record
	shouldRefillDesired := record.Managed && preservedState == "" && isTerminalWorkerState(record.State)
	m.mu.Unlock()
	if shouldRefillDesired {
		go m.refillDesiredWorkersAfterManagedExit(record.ID)
	}
}

var managedWorkerIndexLockOwnerLookup = gitlock.IndexLockOwner

// recoverManagedWorkerIndexLockAfterExit removes a fresh or stale .git/index.lock
// left behind by a managed worker that has already exited, but only when no live
// process still owns the lock. The cleanup is intentionally fresh-lock tolerant:
// once the worker has exited, an unowned lock is safe to remove even if it is
// younger than gitlock.StaleAge.
func recoverManagedWorkerIndexLockAfterExit(projectRoot, workerID string, workerPID int) (WorkerLifecycleEvent, bool) {
	if strings.TrimSpace(projectRoot) == "" {
		return WorkerLifecycleEvent{}, false
	}
	lockPath := gitlock.IndexLockPath(projectRoot)
	if _, err := os.Lstat(lockPath); err != nil {
		return WorkerLifecycleEvent{}, false
	}

	ownerPID, _ := managedWorkerIndexLockOwnerLookup(lockPath)
	outcome := "removed"
	reason := "managed worker exited; no live owner"

	if workerPID > 0 && processAlive(workerPID) {
		outcome = "kept-live-worker"
		reason = fmt.Sprintf("worker pid %d still alive", workerPID)
	} else if ownerPID > 0 && processAlive(ownerPID) {
		outcome = "kept-live-owner"
		reason = fmt.Sprintf("live lock owner pid %d", ownerPID)
	} else if err := os.Remove(lockPath); err != nil && !os.IsNotExist(err) {
		outcome = "remove-error"
		reason = err.Error()
	}

	return WorkerLifecycleEvent{
		Action:    "index-lock-violation",
		Actor:     "ddx-server",
		Timestamp: time.Now().UTC(),
		Detail: fmt.Sprintf(
			"worker=%s worker_pid=%d holder_pid=%d lock_path=%s operation=index.commit outcome=%s reason=%s",
			workerID, workerPID, ownerPID, lockPath, outcome, reason,
		),
	}, true
}

func (m *WorkerManager) refillDesiredWorkersAfterManagedExit(id string) {
	result, err := m.provisionDesiredWorkersBeforeStaleSweep()
	if err != nil {
		_, _ = fmt.Fprintf(os.Stderr, "ddx-server: worker %s desired refill failed: %v\n", id, err)
